// CountIDs returns the count of ids with FGA batch filtering applied
func (sdq *SystemDetailQuery) CountIDs(ctx context.Context) (int, error) {
	logx.FromContext(ctx).Debug().Str("query_type", "SystemDetail").Str("operation", "count_ids").Msg("CountIDs: starting")

	ctx = setContextOp(ctx, sdq.ctx, ent.OpQueryIDs)

	ids, err := sdq.IDs(ctx)
	if err != nil {
		logx.FromContext(ctx).Error().Err(err).Str("query_type", "SystemDetail").Str("operation", "count_ids").Msg("CountIDs: IDs() failed")

		return 0, err
	}

	logx.FromContext(ctx).Debug().Str("query_type", "SystemDetail").Str("operation", "count_ids").Int("count", len(ids)).Msg("CountIDs: completed")

	return len(ids), nil
}

